  flashcards: [
    { front: "What causes all sound?", back: "Vibrations — an object moving quickly back and forth." },
    { front: "What is the medium of a sound wave?", back: "The solid, liquid or gas the wave travels through by making particles vibrate." },
    { front: "Why can't sound travel through a vacuum?", back: "A vacuum has no particles, so there is nothing to pass the vibration along." },
    { front: "What does the bell-jar experiment show?", back: "As air is pumped out the bell can be seen but not heard, proving sound needs a medium." },
    { front: "Speed of sound in air?", back: "About 330–340 m/s." },
    { front: "Is sound faster in solids or gases?", back: "Fastest in solids, slower in liquids, slowest in gases." },
    { front: "Why do you see lightning before hearing thunder?", back: "Light is far faster (about 300,000,000 m/s) than sound (about 340 m/s)." },
    { front: "What does pitch depend on?", back: "Frequency, measured in hertz (Hz). High frequency = high pitch." },
    { front: "What does loudness depend on?", back: "Amplitude — the size of the vibration. Bigger amplitude = louder." },
    { front: "What is amplitude?", back: "The maximum distance a particle (or wave) moves from its rest position." },
    { front: "On an oscilloscope, what shows loudness?", back: "The height of the trace (the amplitude); taller = louder." },
    { front: "Human hearing range?", back: "About 20 Hz to 20,000 Hz." },
    { front: "What is ultrasound?", back: "Sound with a frequency above 20,000 Hz, too high for humans to hear." },
    { front: "What is an echo?", back: "A sound that has reflected (bounced) off a hard surface and returned." },
  ],

